def gen(rng, size):
    n = max(1, size)
    commands = []
    for _ in range(n):
        r = rng.random()
        if r < 0.15:
            commands.append(-1)
        elif r < 0.3:
            commands.append(-2)
        else:
            commands.append(rng.randint(1, 9))
    m = rng.randint(0, 200)
    coords = set()
    obstacles = []
    while len(obstacles) < m:
        x = rng.randint(-50, 50)
        y = rng.randint(-50, 50)
        if (x, y) not in coords:
            coords.add((x, y))
            obstacles.append([x, y])
    return [commands, obstacles]

