class Solution:
    def robotSim(self, commands, obstacles):
        # Brute: same simulation but with an explicit direction index table.
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]  # N, E, S, W
        d = 0
        x = y = 0
        blocked = set((ox, oy) for ox, oy in obstacles)
        best = 0
        for cmd in commands:
            if cmd == -1:
                d = (d + 1) % 4
            elif cmd == -2:
                d = (d - 1) % 4
            else:
                dx, dy = dirs[d]
                for _ in range(cmd):
                    nx, ny = x + dx, y + dy
                    if (nx, ny) in blocked:
                        break
                    x, y = nx, ny
                    if x * x + y * y > best:
                        best = x * x + y * y
        return best

