class Solution:
    def robotSim(self, commands, obstacles):
        dx, dy = 0, 1
        x = y = 0
        obs = set(map(tuple, obstacles))
        best = 0
        for cmd in commands:
            if cmd == -1:
                dx, dy = dy, -dx
            elif cmd == -2:
                dx, dy = -dy, dx
            else:
                for _ in range(cmd):
                    nx, ny = x + dx, y + dy
                    if (nx, ny) in obs:
                        break
                    x, y = nx, ny
                    best = max(best, x * x + y * y)
        return best

