var robotSim = function(commands, obstacles) {
    let dx = 0, dy = 1, x = 0, y = 0, best = 0;
    const obs = new Set(obstacles.map(([a, b]) => a + ',' + b));
    for (const cmd of commands) {
        if (cmd === -1) {
            [dx, dy] = [dy, -dx];
        } else if (cmd === -2) {
            [dx, dy] = [-dy, dx];
        } else {
            for (let i = 0; i < cmd; i++) {
                const nx = x + dx, ny = y + dy;
                if (obs.has(nx + ',' + ny)) break;
                x = nx; y = ny;
                best = Math.max(best, x * x + y * y);
            }
        }
    }
    return best;
};
